import { useState } from "react";


export default function Contact() {

  const handleSubmit = async (e) => {
  e.preventDefault();

  await fetch("http://localhost:5000/contacts", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(form),
  });

  alert("Message saved successfully!");
};


const [form, setForm] = useState({
  name: "",
  email: "",
  message: "",
});

const handleChange = (e) => {
  setForm({ ...form, [e.target.name]: e.target.value });
};
  return (
    <section className="contact-container">

      <div className="contact-form">
        <h2>Get In Touch</h2>

        <input type="text" placeholder="Your Name" />
        <input type="email" placeholder="Your Email" />
        <textarea rows="5" placeholder="Your Message"></textarea>

        <button>Send Message</button>
      </div>

      <div className="contact-info">
        <h3>Contact Details</h3>
        <p><strong>Phone:</strong> 9324035816</p>
        <p><strong>Email:</strong> kanchan@stellartalentbridge.in</p>

        <iframe
          src="https://maps.google.com/maps?q=india&t=&z=13&ie=UTF8&iwloc=&output=embed"
          title="map"
        ></iframe>
      </div>

    </section>


  );
}
